import{_ as i,c as a,o as t,ae as e}from"./chunks/framework.CDjunVez.js";const n="/assets/running.m8cjXGkD.png",l="/assets/ssl_warning.D8uIPP_N.png",o="/assets/ssl_click.Di9yGIcI.png",r="/assets/ssl_warning_firefox.BS5UUqWO.png",p="/assets/https.z2GKJtl0.png",f=JSON.parse('{"title":"Installation","description":"","frontmatter":{},"headers":[],"relativePath":"introduction/install.md","filePath":"introduction/install.md"}'),h={name:"introduction/install.md"};function c(d,s,u,g,k,b){return t(),a("div",null,[...s[0]||(s[0]=[e(`<h1 id="installation" tabindex="-1">Installation <a class="header-anchor" href="#installation" aria-label="Permalink to &quot;Installation&quot;">​</a></h1><h3 id="linux-distributions" tabindex="-1">Linux Distributions <a class="header-anchor" href="#linux-distributions" aria-label="Permalink to &quot;Linux Distributions&quot;">​</a></h3><p>KiwiPanel supports non-EOL Linux distributions officially supported by OpenLiteSpeed.</p><ul><li>Debian 12, 13</li><li>Ubuntu LTS 22.04, 24.04</li><li>Rocky Linux 9, 10</li><li>AlmaLinux 9, 10</li><li>RHEL 9 and compatible derivatives</li></ul><p>CentOS Stream and EOL distributions are not supported.</p><h3 id="windows-and-mac-distributions-not-supported" tabindex="-1">Windows and Mac Distributions: Not Supported <a class="header-anchor" href="#windows-and-mac-distributions-not-supported" aria-label="Permalink to &quot;Windows and Mac Distributions: Not Supported&quot;">​</a></h3><h2 id="prerequisites" tabindex="-1">Prerequisites <a class="header-anchor" href="#prerequisites" aria-label="Permalink to &quot;Prerequisites&quot;">​</a></h2><ul><li>Fresh VPS with supported OSs.</li><li>Minimum &gt;=512MB RAM</li><li>Minimum &gt;=1GB disk space</li><li>Root access</li></ul><h2 id="install" tabindex="-1">Install <a class="header-anchor" href="#install" aria-label="Permalink to &quot;Install&quot;">​</a></h2><p>If you are installing Kiwipanel on Debian or the distro that does not have <code>curl</code> by default, run this command first:</p><div class="language-bash vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">sudo</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> apt</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> update</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;"> &amp;&amp; </span><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">sudo</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> apt</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> install</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> curl</span></span></code></pre></div><p><strong>Quick install (advanced users):</strong></p><div class="language-bash vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">bash</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> &lt;(</span><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">curl</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> -fsSL</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> https://raw.githubusercontent.com/kiwipanel/install/main/install)</span></span></code></pre></div><p><strong>Recommended (review before install):</strong></p><div class="language-bash vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">curl</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> -sLO</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> https://raw.githubusercontent.com/kiwipanel/install/main/install</span></span>
<span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">chmod</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> +x</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> install</span></span>
<span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">sudo</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> bash</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> install</span></span></code></pre></div><h2 id="successul-installation" tabindex="-1">Successul Installation <a class="header-anchor" href="#successul-installation" aria-label="Permalink to &quot;Successul Installation&quot;">​</a></h2><p>If the installation is successful, visit http://YOUR_SERVER_IP (<b style="color:red;"><strong>NOT</strong> https </b>), you will see the following information:</p><p><img src="`+n+'" alt="An image"></p><h2 id="🔐-self-signed-ssl-initial-access" tabindex="-1">🔐 Self-Signed SSL (Initial Access) <a class="header-anchor" href="#🔐-self-signed-ssl-initial-access" aria-label="Permalink to &quot;🔐 Self-Signed SSL (Initial Access)&quot;">​</a></h2><p>KiwiPanel automatically generates a self-signed SSL certificate after installation to secure the admin panel.</p><ul><li><strong>Port:</strong> <code>8443</code></li><li><strong>SSL Path:</strong> <code>/etc/kiwipanel/ssl/</code></li><li><strong>Validity:</strong> 10 years</li><li><strong>Issued for:</strong> Server IP address</li></ul><h3 id="access-the-panel" tabindex="-1">Access the Panel <a class="header-anchor" href="#access-the-panel" aria-label="Permalink to &quot;Access the Panel&quot;">​</a></h3><p>https://YOUR_SERVER_IP:8443/PASSCODE</p><blockquote><p>⚠️ Browser warnings are expected because the certificate is self-signed.<br> Click <strong>Advanced → Continue</strong> to proceed.</p></blockquote><p><img src="'+l+'" alt="An image"></p><p>Then you will see a &quot;warning&quot; from the browser. That is expected because we are using a self-sign certificate. Hit the &quot;Proceed to YOUR_SERVER_IP (unsafe)&quot; button.</p><p><img src="'+o+'" alt="An image"></p><p>This is the warning on <strong>Firefox</strong>. You can ignore it and proceed to the panel by clicking on &quot;Advanced...&quot; button and then on &quot;Accept the Risk and Continue&quot;.</p><p><img src="'+r+'" alt="An image"></p><h3 id="caveat" tabindex="-1">Caveat: <a class="header-anchor" href="#caveat" aria-label="Permalink to &quot;Caveat:&quot;">​</a></h3><p>-❌ Accessing to https://YOUR_SERVER_IP, you get refusal because there is not self-sign certificate for the IP.</p><p>-✅ You should use http://YOUR_SERVER_IP.</p><p>-❌ Accessing to http://YOUR_SERVER_IP:8443 is not recommended because it is not secure. You will see a &quot;warning&quot; from the browser or might be a blank depending on the browser.</p><p><img src="'+p+'" alt="An image"></p><p>-❌ Accessing to https://YOUR_SERVER_IP:8443, you get 404 Not Found. It means the webpanel is properly configured. That is expected by design.</p><p>-✅ You should use https://YOUR_SERVER_IP:8443/PASSCODE instead.</p><h3 id="firewall" tabindex="-1">Firewall <a class="header-anchor" href="#firewall" aria-label="Permalink to &quot;Firewall&quot;">​</a></h3><ul><li>Port <code>8443</code> is used for the admin panel</li><li>Port <code>443</code> is opened for future Let’s Encrypt SSL certificates</li></ul><h3 id="log" tabindex="-1">Log <a class="header-anchor" href="#log" aria-label="Permalink to &quot;Log&quot;">​</a></h3><p>Type the command <code>cat /opt/kiwipanel/logs/install.log</code> to see the installation log in case you encounter any issues.</p><h2 id="next-step" tabindex="-1">Next Step <a class="header-anchor" href="#next-step" aria-label="Permalink to &quot;Next Step&quot;">​</a></h2><p>In the future, you might assign a domain and enable <strong>Let’s Encrypt SSL</strong> to replace the self-signed certificate. But for now, you can use the self-signed certificate for accessing to your admin panel, which is totally safe and normal given that we can assign a ssl certificate to a domain only, not IP.</p>',42)])])}const F=i(h,[["render",c]]);export{f as __pageData,F as default};
